/*
 * rint() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly rint  (test_rint_opt.elf)
 *   2. Linked with toolchain's default rint        (test_rint_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += rint(vx);
#else
    double r = rint(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* 100 representative test points                                      */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(DBL_MIN);   /* smallest positive normal: 2^-1022 = 0x0010000000000000 */
    emit(-DBL_MIN);
    emit(DBL_MAX);   /* largest finite double: 0x7fefffffffffffff */
    emit(-DBL_MAX);

    /* --- Section 4: Exact half-integers (round-to-even stress) (14) --- */
    emit(0.5);    /* rounds to 0.0 (even) */
    emit(-0.5);   /* rounds to -0.0 (even) */
    emit(1.5);    /* rounds to 2.0 (even) */
    emit(-1.5);   /* rounds to -2.0 (even) */
    emit(2.5);    /* rounds to 2.0 (even) */
    emit(-2.5);   /* rounds to -2.0 (even) */
    emit(3.5);    /* rounds to 4.0 (even) */
    emit(-3.5);   /* rounds to -4.0 (even) */
    emit(4.5);    /* rounds to 4.0 (even) */
    emit(-4.5);   /* rounds to -4.0 (even) */
    emit(5.5);    /* rounds to 6.0 (even) */
    emit(-5.5);   /* rounds to -6.0 (even) */
    emit(100.5);  /* rounds to 100.0 (even) */
    emit(-100.5); /* rounds to -100.0 (even) */

    /* --- Section 5: ULP neighbors of 0.5 and 1.5 (8) --- */
    emit_u(0x3fdffffffffffffeULL);  /* one ULP below 0.5 */
    emit_u(0x3fe0000000000000ULL);  /* exactly 0.5 (already done above; distinct bit pattern ref) */
    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
    emit_u(0xbfdffffffffffffeULL);  /* one ULP toward zero from -0.5 */
    emit_u(0x3ff7ffffffffffffULL);  /* one ULP below 1.5 */
    emit_u(0x3ff8000000000000ULL);  /* exactly 1.5 (bit pattern: 1.5) */
    emit_u(0x3ff8000000000001ULL);  /* one ULP above 1.5 */
    emit_u(0xbff8000000000001ULL);  /* one ULP away from zero from -1.5 */

    /* --- Section 6: Fractional values in (0, 2) (10) --- */
    emit(0.1);
    emit(0.2);
    emit(0.3);
    emit(0.4);
    emit(0.6);
    emit(0.7);
    emit(0.8);
    emit(0.9);
    emit(1.1);
    emit(1.9);

    /* --- Section 7: Negative fractional values in (-2, 0) (8) --- */
    emit(-0.1);
    emit(-0.2);
    emit(-0.4);
    emit(-0.6);
    emit(-0.7);
    emit(-0.9);
    emit(-1.1);
    emit(-1.9);

    /* --- Section 8: Medium integer and fractional values (10) --- */
    emit(1.0);
    emit(-1.0);
    emit(2.0);
    emit(-2.0);
    emit(3.0);
    emit(-3.0);
    emit(1.0000000000000002);   /* 1.0 + 1 ULP: 0x3ff0000000000001 */
    emit(-1.0000000000000002);  /* -(1.0 + 1 ULP) */
    emit(0.9999999999999999);   /* 1.0 - 1 ULP: 0x3fefffffffffffff */
    emit(-0.9999999999999999);  /* -(1.0 - 1 ULP) */

    /* --- Section 9: Large values where double has no fractional bits (8) --- */
    /* 2^52 = 4503599627370496.0: all doubles >= 2^52 are exact integers */
    emit_u(0x4330000000000000ULL);  /* 2^52: smallest double with no fractional part */
    emit_u(0x4330000000000001ULL);  /* 2^52 + 1 ULP */
    emit_u(0xc330000000000000ULL);  /* -(2^52) */
    emit(1.0e15);
    emit(-1.0e15);
    emit(1.0e16);
    emit(DBL_MAX / 2.0);   /* large but not overflow */
    emit(-DBL_MAX / 2.0);

    /* --- Section 10: Tiny inputs that round to 0.0 (6) --- */
    emit(1.0e-10);
    emit(-1.0e-10);
    emit(1.0e-100);
    emit(-1.0e-100);
    emit(1.0e-300);
    emit(-1.0e-300);

    /* --- Section 11: ULP neighbors of exact half-integers (10) --- */
    /* 2.5 is 0x4004000000000000; test neighbors */
    emit_u(0x4003ffffffffffffULL);  /* one ULP below 2.5 */
    emit_u(0x4004000000000001ULL);  /* one ULP above 2.5 */
    /* 3.5 is 0x400c000000000000; test neighbors */
    emit_u(0x400bffffffffffffULL);  /* one ULP below 3.5 */
    emit_u(0x400c000000000001ULL);  /* one ULP above 3.5 */
    /* 0.4999999999999999 and 0.5000000000000001 */
    emit_u(0x3fdffffffffffffeULL);  /* 0.5 - 2 ULP */
    emit_u(0x3fe0000000000002ULL);  /* 0.5 + 2 ULP */
    /* near -0.5 */
    emit_u(0xbfe0000000000000ULL);  /* exactly -0.5 */
    emit_u(0xbfe0000000000001ULL);  /* one ULP away from zero from -0.5 */
    /* near 10.5: 0x4025000000000000 */
    emit_u(0x4024ffffffffffffULL);  /* one ULP below 10.5 */
    emit_u(0x4025000000000001ULL);  /* one ULP above 10.5 */

    /* --- Section 12: Powers of 2 and near neighbors (9) --- */
    emit_u(0x3fe0000000000000ULL);  /* 0.5 = 2^-1 */
    emit_u(0x4000000000000000ULL);  /* 2.0 = 2^1 */
    emit_u(0x4010000000000000ULL);  /* 4.0 = 2^2 */
    emit_u(0x4020000000000000ULL);  /* 8.0 = 2^3 */
    emit_u(0x4024000000000000ULL);  /* 10.0 */
    emit_u(0x3ff0000000000000ULL);  /* 1.0 = 2^0 */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    emit_u(0xbff0000000000000ULL);  /* -1.0 */
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep [0, 10] in 100 steps and [-10, 0] in 100 steps */
static void test_sweep(void)
{
    double hi = 10.0;
    int nsteps = 100;
    double step = hi / (double)nsteps;

    /* [0, 10] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);

    /* [-10, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);
}

/* 8. Sample [0, 10] every ~0.05 (200 points) */
static void test_exhaustive_small(void)
{
    double hi = 10.0;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf result: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}
